var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"상황은 어떤가요?","JPN":"状況はどうですか？","ENG":"What's the situation?","TWN":"情況怎麼樣？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"한숨은 돌렸어.","JPN":"一息ついたところだ。","ENG":"We've fended them off for now.","TWN":"暫時鬆了口氣。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"하지만 녀석들이 이 정도로 포기할 것 같진 않군.","JPN":"しかし、やつらがこの程度で断念することはないだろう。","ENG":"But I don't think they’re ready to give up just yet.","TWN":"但是那些傢伙們不會就這樣放棄的。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"미확인 고속 비행체 다수!","JPN":"未確認の高速飛行体、多数！","ENG":"Multiple bogeys coming in fast!","TWN":"出現大量不明高速飛行體！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"본 함을 중심으로 접근 중입니다.","JPN":"本艦を目標に接近しています。","ENG":"They’re approaching our ship.","TWN":"正以本艦為中心接近。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"20분 이내에 교전 거리 내로 진입할 것 같습니다.","JPN":"20分以内に交戦距離内に進入しそうです。","ENG":"They’ll be within strike range in 20 minutes.","TWN":"20分鐘以內會進入交戰距離。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......들었지? 아무래도 긴 하루가 될 것 같아.","JPN":"聞こえたか？　どうやら長い一日になりそうだ。","ENG":"Hear that? It’s going to be a long day.","TWN":"……聽到了吧？不管怎樣，今天都會是漫長的一天。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......리플레이서 비숍의 상태는요?","JPN":"……リプレイサー・ビショップの状態は？","ENG":"How’s the Replacer Bishop doing?","TWN":"……克隆·大主教的情況怎麼樣了？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"집중치료실에서 간호 중이다.","JPN":"集中治療室で看てもらっている。","ENG":"Receiving treatment in the intensive care unit.","TWN":"正在集中治療室接受治療。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"쇠약해지긴 했지만...... 뭐, 죽을 것 같진 않군.","JPN":"衰弱してはいるが……まあ、命に別条は無さそうだ。","ENG":"Although she's grown more frail... She’ll probably make it.","TWN":"雖然變得很衰弱……不過應該不會死。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그 정도로는 부족해!","JPN":"その程度じゃ足りないわ！","ENG":"That’s not enough!","TWN":"這樣不夠！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"최소한 정보를 뱉어낼 정도의 의식과 체력은 유지해야 한다고!","JPN":"情報を吐き出せるほどの意識と体力は維持させないと！","ENG":"You need to keep her alert and energetic enough to spit out the intel we need at the very least!","TWN":"至少要維持可以招供情報的意識和體力！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그런 건 리플레이서 놈들에게나 말해. 이쪽은 최선을 다하고 있다고.","JPN":"そんなのはリプレイサーどもに言え。\\nこっちは最善を尽くしてるんだ。","ENG":"Tell that to the Replacer. We’re trying our best here.","TWN":"這種事妳還是和克隆集團的傢伙們說吧。我們已經盡力了。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"대체 왜 리플레이서가 비숍을 노리는 걸까요?","JPN":"いったいなぜ、リプレイサーがビショップを狙うのでしょうか。","ENG":"Why on earth would the Syndicate go after the Bishop?","TWN":"克隆集團到底為什麼會盯上克隆·大主教？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L23_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"구출이라면 모르지만 사살 명령을 내린 건 너무 극단적이군요.","JPN":"救出ならともかく、射殺命令が\\n出されたのは極端すぎますね。","ENG":"I can see why they'd try to rescue her, but authorizing lethal force seems a bit extreme, even for them.","TWN":"雖然不知道他們是不是在救人，但是直接擊斃也太極端了。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L25_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"목격자의 말에 따르면 비숍을 배신자라고 불렀다더군.","JPN":"目撃者の話によると、ビショップを裏切り者と呼んでいたそうだ。","ENG":"Witnesses say the Replacers called the Bishop a traitor.","TWN":"根據目擊者的證詞，克隆·大主教被叫成叛徒。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"만약 비숍이 정말 배신한 거라면 놈들의 계획에는 치명적일 테니, 제거에 필사적일 수밖에.","JPN":"もしビショップが本当に裏切ったのであれば、\\nやつらの計画には致命的だろうから、排除しようと躍起になるだろう。","ENG":"If the Bishop did in fact betray them, that could ruin their plans. So she had to be removed.","TWN":"要是克隆·大主教真的背叛他們的話，就會對克隆集團的計畫造成致命的影響，所以他們才會這麼拼命地想要除掉大主教。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};